appendEvent: (event) => {
  set((s) => {
    if (s.eventIds.has(event.id)) return s;
    const nextEvents = [event, ...s.events].slice(0, MAX_EVENTS_BUFFER);
    const eventIds = new Set(nextEvents.map(e => e.id));
    return { events: nextEvents, eventIds };
  });
}

